import test from 'node:test';
import assert from 'node:assert/strict';
import { WorkflowOrchestrator } from './orchestrator.js';

const sleep = ms => new Promise(resolve => setTimeout(resolve, ms));

test('runs ordered workflow steps and stores outputs', async () => {
  const o = new WorkflowOrchestrator({ concurrency: 2 });
  o.register('double', async input => input * 2);
  o.register('inc', async input => input + 1);
  const id = o.submit({ input: 3, steps: [{ task: 'double' }, { task: 'inc' }] });
  await o.drain();
  const job = o.getJob(id);
  assert.equal(job.status, 'succeeded');
  assert.deepEqual(job.outputs, [6, 7]);
});

test('retries failed steps and records attempts', async () => {
  const o = new WorkflowOrchestrator({ concurrency: 1, retryDelayMs: 1 });
  let calls = 0;
  o.register('flaky', async value => { calls++; if (calls < 3) throw new Error('temporary'); return value; });
  const id = o.submit({ input: 'ok', steps: [{ task: 'flaky', retries: 2 }] });
  await o.drain();
  const job = o.getJob(id);
  assert.equal(job.status, 'succeeded');
  assert.equal(calls, 3);
  assert.equal(job.steps[0].attempts.length, 3);
});

test('honors concurrency limit while processing multiple jobs', async () => {
  const o = new WorkflowOrchestrator({ concurrency: 2 });
  let active = 0;
  let maxActive = 0;
  o.register('slow', async value => { active++; maxActive = Math.max(maxActive, active); await sleep(20); active--; return value; });
  for (let i = 0; i < 5; i++) o.submit({ input: i, steps: [{ task: 'slow' }] });
  await o.drain();
  assert.equal(maxActive <= 2, true);
  assert.equal([...o.jobs.values()].every(j => j.status === 'succeeded'), true);
});

test('emits structured lifecycle events', async () => {
  const o = new WorkflowOrchestrator();
  const events = [];
  o.on('event', event => events.push(event));
  o.register('echo', async x => x);
  const id = o.submit({ input: 'x', steps: [{ task: 'echo' }] });
  await o.drain();
  assert.equal(events.some(e => e.type === 'job:queued' && e.jobId === id), true);
  assert.equal(events.some(e => e.type === 'job:succeeded' && e.jobId === id), true);
  assert.equal(events.every(e => typeof e.timestamp === 'number'), true);
});
